def trap_prefix(self, h: list[int]) -> int:
    n = len(h)
    if n < 3:
        return 0
    L = [0] * n
    R = [0] * n
    L[0] = h[0]
    for i in range(1, n):
        L[i] = max(L[i - 1], h[i])
    R[-1] = h[-1]
    for i in range(n - 2, -1, -1):
        R[i] = max(R[i + 1], h[i])
    return sum(min(L[i], R[i]) - h[i] for i in range(n))

def trap(self, h: list[int]) -> int:
    l, r = 0, len(h) - 1
    lmax = rmax = ans = 0
    while l < r:
        if h[l] < h[r]:
            lmax = max(lmax, h[l])
            ans += lmax - h[l]
            l += 1
        else:
            rmax = max(rmax, h[r])
            ans += rmax - h[r]
            r -= 1
    return ans

def trap_stack(self, h: list[int]) -> int:
    st: list[int] = []
    ans = 0
    for i, x in enumerate(h):
        while st and h[st[-1]] < x:
            bottom = st.pop()
            if not st:
                break
            left = st[-1]
            w = i - left - 1
            ans += w * (min(h[left], x) - h[bottom])
        st.append(i)
    return ans
